        let result = create_diff("hello", "hello world");
        assert!(result.is_ok());
    }
}

//! phenotype-patch - Unified diff parsing and application library
//!
//! Provides parsing, application, creation, and merging of unified diffs.

pub mod parse;
pub mod apply;
pub mod create;
pub mod merge;

use thiserror::Error;

pub use parse::{ParseError, parse_diff, Hunk};
pub use apply::{ApplyError, apply_patch};

/// Represents a parsed unified diff
#[derive(Debug, Clone)]
pub struct Diff {
    pub hunks: Vec<Hunk>,
}

/// Result type for diff creation
pub type CreateResult<T = Diff> = Result<T, CreateError>;

/// Error types for diff creation
#[derive(Debug, Error)]
pub enum CreateError {
    #[error("empty content provided")]
    EmptyContent,
    #[error("diff creation failed: {0}")]
    CreationFailed(String),
}

//! Merge conflicting diffs.

use std::fmt;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MergeChoice {
    Ours,
    Theirs,
    Both,
}

#[derive(Debug, Clone)]
pub struct Conflict {
    pub ours: String,
    pub theirs: String,
}

#[derive(Debug, Clone)]
pub struct MergeSuccess {
    pub merged: String,
    pub has_conflicts: bool,
}

/// Merge multiple patches, handling conflicts.
pub fn merge_patches(base: &str, patches: &[(&str, &str)]) -> Result<MergeSuccess, String> {
    let mut result = base.to_string();

    for (_, patch) in patches {
        let has_conflicts = patch.contains("<<<<<<<")
            || patch.contains("=======")
            || patch.contains(">>>>>>>");

        result.push_str(patch);

        if has_conflicts {
            return Ok(MergeSuccess {
                merged: result,
                has_conflicts: true,
            });
        }
    }

    Ok(MergeSuccess {
        merged: result,
        has_conflicts: false,
    })
}

impl fmt::Display for MergeChoice {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            MergeChoice::Ours => write!(f, "ours"),
            MergeChoice::Theirs => write!(f, "theirs"),
            MergeChoice::Both => write!(f, "both"),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-PATCH-004
    #[test]
    fn test_merge_no_conflicts() {
        let base = "line1\nline2\n";
        let patches = vec![("", "+line3\n")];
        let result = merge_patches(base, &patches).unwrap();
        assert!(!result.has_conflicts);
        assert!(result.merged.contains("line3"));
    }
}

//! Unified diff parsing.

use thiserror::Error;

#[derive(Debug, Clone, PartialEq)]
pub struct Hunk {
    pub old_start: usize,
    pub new_start: usize,
    pub old_lines: usize,
    pub new_lines: usize,
    pub lines: Vec<String>,
}

#[derive(Debug, Error)]
pub enum ParseError {
    #[error("Invalid hunk header: {0}")]
    InvalidHeader(String),
    #[error("Unexpected end of input")]
    UnexpectedEof,
    #[error("Missing context line: {0}")]
    MissingContext(String),
}

/// Parse a unified diff string into hunks.
pub fn parse_diff(diff: &str) -> Result<Vec<Hunk>, ParseError> {
    let mut hunks = Vec::new();
    let mut lines = diff.lines().peekable();
    let mut current_hunk: Option<Hunk> = None;

    while let Some(line) = lines.next() {
        if line.starts_with("@@") {
            if let Some(h) = current_hunk.take() {
                hunks.push(h);
            }

            let parts: Vec<&str> = line.split_whitespace().collect();
            if parts.len() < 3 {
                return Err(ParseError::InvalidHeader(line.to_string()));
            }

            let old_part = parts[1].trim_start_matches('-');
            let new_part = parts[2].trim_start_matches('+');

            let (old_start, old_lines) = parse_range(old_part)?;
            let (new_start, new_lines) = parse_range(new_part)?;

            current_hunk = Some(Hunk {
                old_start,
                new_start,
                old_lines,
                new_lines,
                lines: Vec::new(),
            });
        } else if let Some(ref mut hunk) = current_hunk {
            hunk.lines.push(line.to_string());
        }
    }

    if let Some(h) = current_hunk {
        hunks.push(h);
    }

    Ok(hunks)
}

fn parse_range(s: &str) -> Result<(usize, usize), ParseError> {
    let parts: Vec<&str> = s.split(',').collect();
    match parts.len() {
        1 => {
            let start: usize = parts[0].parse().unwrap_or(1);
            Ok((start, 1))
        }
        2 => {
            let start: usize = parts[0].parse().unwrap_or(1);
            let count: usize = parts[1].parse().unwrap_or(1);
            Ok((start, count))
        }
        _ => Err(ParseError::InvalidHeader(s.to_string())),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-PATCH-006
    #[test]
    fn test_parse_diff() {
        let diff = r#"--- a/file.txt
+++ b/file.txt
@@ -1,3 +1,4 @@
 line1
-old
+new
 line3
+added
@@ -10,2 +12,1 @@
 context
-old2
+new2
"#;
        let hunks = parse_diff(diff).unwrap();
        assert_eq!(hunks.len(), 2);
        assert_eq!(hunks[0].old_start, 1);
        assert_eq!(hunks[0].new_start, 1);
    }
}
